import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"16. Disciplinary Procedure","description":"","frontmatter":{"title":"16. Disciplinary Procedure","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["discipline","union-matters"]},"headers":[],"relativePath":"ebas/mspp/disputes/16-disciplinary-procedure.md","filePath":"ebas/mspp/disputes/16-disciplinary-procedure.md"}'),i={name:"ebas/mspp/disputes/16-disciplinary-procedure.md"};function s(a,e,p,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_16-disciplinary-procedure" tabindex="-1">16. Disciplinary Procedure <a class="header-anchor" href="#_16-disciplinary-procedure" aria-label="Permalink to &quot;16. Disciplinary Procedure&quot;">​</a></h1><p><strong>16.1</strong> Application</p><p><strong>a.</strong> Except as provided at 16.7, where an Employer has concerns about:</p><p><strong>(i)</strong> the Conduct of an Employee; or</p><p><strong>(ii)</strong> a performance issue that may constitute Misconduct, the following procedure will apply.</p><p><strong>b.</strong> There are two steps in a disciplinary process under this clause as follows:</p><p><strong>(i)</strong> investigative procedure; and</p><p><strong>(ii)</strong> disciplinary procedure.</p><p><strong>c.</strong> An Employee will be provided a reasonable opportunity to be represented at any time (including by a Union) with respect to all matters set out in this clause.</p><p><strong>d.</strong> The Employer will notify the Employee in accordance with sub-clause 16.3b as soon as practicable following the Employer becoming aware of concerns set out at sub-clause 16.1a.</p><p><strong>16.2</strong> Definitions</p><p><strong>a.</strong> Performance means the manner in which the Employee fulfils their job requirements. The level of performance is determined by an Employee’s knowledge, skills, qualifications, abilities and the requirements of the role.</p><p><strong>b.</strong> Where there are concerns regarding Performance that does not meet the definition of Misconduct at subclause 16.2d, <a href="/eba/ebas/allied-health/consultation-disputes/15-performance-management.html">clause 15</a> will apply.</p><p><strong>c.</strong> Conduct means the manner in which the Employee behaviour impacts on their work.</p><p><strong>d.</strong> Misconduct means an Employee’s intentional or negligent failure to abide by or adhere to the standards of conduct reasonably expected by the Employer. A</p><p>Performance issue can be considered Misconduct where, despite all reasonably practicable interventions by the Employer, the Employee refuses to undertake all or part of their job requirements to a satisfactory level.</p><p><strong>e.</strong> Serious misconduct is as defined under the Act and that is both wilful and deliberate. Currently, the Act defines serious misconduct, in part, as:</p><p><strong>(i)</strong> wilful or deliberate behaviour by an Employee that is inconsistent with the continuation of the contract of employment;</p><p><strong>(ii)</strong> conduct that causes serious and imminent risk to: <strong>(A)</strong> the health or safety of a person; or <strong>(B)</strong> the reputation, viability or profitability of the Employer’s business.</p><p><strong>f.</strong> Conduct that is serious misconduct includes each of the following:</p><p><strong>(i)</strong> the Employee, in the course of the Employee&#39;s employment, engaging in: <strong>(A)</strong> theft; or <strong>(B)</strong> fraud; or <strong>(C)</strong> assault; or <strong>(D)</strong> sexual harassment;</p><p><strong>(ii)</strong> the Employee being intoxicated at work;</p><p><strong>(iii)</strong> the Employee refusing to carry out a lawful and reasonable instruction that is consistent with the Employee&#39;s contract of employment, save for exemptions under the OHS Act and the Act.</p><p><strong>g.</strong> Subclauses 16.2f(i)-16.2f(iii) do not apply if the Employee is able to show that, in the circumstances, the conduct engaged in by the Employee was not conduct that made employment in the period of notice unreasonable.</p><p><strong>16.3</strong> Investigative procedure</p><p><strong>a.</strong> The purpose of an investigative procedure is to conclude whether, on balance, concerns regarding Conduct (or a Performance matter that meets the definition of Misconduct in clause 16.2d) are well-founded and supported by evidence. An investigation procedure must be fair including proper regard to procedural fairness.</p><p><strong>b.</strong> The Employer will:</p><p><strong>(i)</strong> advise the Employee of the concerns and allegations in writing;</p><p><strong>(ii)</strong> provide the Employee with any material which forms the basis of the concerns before seeking a response;</p><p><strong>(iii)</strong> ensure the Employee is provided a reasonable opportunity to answer any concerns, including a reasonable time to respond;</p><p><strong>(iv)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(v)</strong> ensure that the reason for any interview is explained; and</p><p><strong>(vi)</strong> take reasonable steps to investigate the Employee’s response.</p><p><strong>c.</strong> Where the Employer has complied with subclauses 16.3b(i)-b(iv) and the Employee does not dispute the concerns, the Employee may opt to decline the opportunity to be interviewed.</p><p><strong>d.</strong> Where the Employee opts to decline the opportunity to be interviewed, the Employee may still raise matters under subclause 16.4c, including matters in mitigation if a disciplinary procedure (see subclause 16.4) is proposed.</p><p><strong>e.</strong> The Employer shall not de-identify complainants other than in exceptional circumstances where there is a risk to the personal safety of the complainant if their identity were disclosed.</p><p><strong>16.4</strong> Disciplinary Procedure</p><p><strong>a.</strong> This procedure applies if, following the investigation: the Employer reasonably considers that the Employee’s Conduct (or a Performance matter that meets the definition of Misconduct in subclause 16.2d) may warrant disciplinary steps being taken.</p><p><strong>b.</strong> The Employer will:</p><p><strong>(i)</strong> notify the Employee in writing of the outcome of the investigation process, including providing a copy of the report and the basis of any conclusion; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to address the matters in subclause 16.4c</p><p><strong>c.</strong> In considering whether to take disciplinary action, the Employer will consider:</p><p><strong>(i)</strong> whether there is a valid reason related to the Conduct or Performance of the Employee arising from the investigation justifying disciplinary action;</p><p><strong>(ii)</strong> whether the Employee knew or ought to have known that the Conduct or Performance was below acceptable standards; and</p><p><strong>(iii)</strong> any explanation by the Employee relating to Conduct including any matters raised in mitigation.</p><p><strong>16.5</strong> Possible outcomes</p><p><strong>a.</strong> Where it is determined that after following the procedures in this clause 16 that disciplinary action is warranted, the Employer may take any of the following steps depending on the seriousness of the Conduct or Performance and shall be recorded on the Employee’s personnel file:</p><p><strong>(i)</strong> where the Performance or Conduct issue does not constitute Serious Misconduct: <strong>(A)</strong> counsel the Employee; <strong>(B)</strong> give the Employee a first written warning; <strong>(C)</strong> give the Employee a second written warning in the event that the Employee has previously been given a first warning within the previous 12 months for that course of conduct; <strong>(D)</strong> give the Employee a final written warning in the event that the Employee has previously been given a second written warning within the preceding 18 month period for that course of conduct; or</p><p><strong>(E)</strong> terminate the Employee’s employment on notice in the case of an Employee who repeats a course of conduct for which a final warning was given in the preceding 18 months;</p><p><strong>(ii)</strong> for Serious Misconduct: <strong>(A)</strong> terminate the Employee’s employment without notice; or <strong>(B)</strong> alternatively, issue the Employee with a final warning without following the steps in subclauses 16.5a(i)(A)- (i)(D)</p><p><strong>b.</strong> The Employer’s decision and a summary of its reasons will be notified to the Employee in writing.</p><p><strong>c.</strong> If after any warning, a period of 12 or 18 months elapses (as relevant) without any further warning being required, all adverse reports relating to the warning must be removed from the Employee&#39;s personnel file.</p><p><strong>16.6</strong> Disputes</p><p><strong>a.</strong> A dispute over clause 16 (including subclause 16.7) is to be dealt with in accordance with the Dispute Resolution Procedure set out at <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> of this Agreement.</p><p><strong>16.7</strong> Exception – Employees who have not completed a minimum period of employment with their Employer</p><p><strong>a.</strong> Where an Employee has not completed a period of employment with their Employer of at least the minimum employment period defined at s.383 of the Act and the Employer is considering the termination of the Employee’s employment, the Employer will:</p><p><strong>(i)</strong> provide the concerns in writing to the Employee as soon as practicable following the Employer becoming aware of the concerns;</p><p><strong>(ii)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(iii)</strong> other than in the case of Serious Misconduct, provide the Employee an opportunity to improve their Performance or Conduct;</p><p><strong>(iv)</strong> meet with the Employee (and, where relevant, their representative); and</p><p><strong>(v)</strong> consider any explanation by the Employee, including any matters raised in mitigation, before making a decision to terminate the employment.</p><p><strong>b.</strong> The terms of subclauses 16.3 to 16.5 inclusive do not apply to Employees within the scope of the exception in this subclause 16.7.</p><p>Plain language terms: discipline, misconduct.</p>',63)])])}const m=t(i,[["render",s]]);export{g as __pageData,m as default};
